const incoming = $input.first()?.json ?? {};
const body = incoming.body ?? incoming;

function firstPresent(...values) {
  return values.find(value => value !== undefined && value !== null);
}

function asArray(value) {
  if (Array.isArray(value)) return value;
  if (value === undefined || value === null || value === "") return [];
  return [value];
}

function compact(value) {
  return asArray(value).map(v => String(v).trim()).filter(Boolean);
}

function numberOrNull(value) {
  const n = Number(value);
  return Number.isFinite(n) ? n : null;
}

function timePressure(totalHours, daysLeft) {
  const total = numberOrNull(totalHours);
  const days = numberOrNull(daysLeft);
  if (total === null && days === null) return "unknown";
  if ((total !== null && total <= 8) || (days !== null && days <= 2)) return "high";
  if ((total !== null && total <= 20) || (days !== null && days <= 5)) return "medium";
  return "low";
}

const evidenceFusionMap = firstPresent(body.evidence_fusion_map, body.evidenceFusionMap, body.fusion_map, body.fusionMap, body.evidence_fusion_agent_output, body.evidenceFusionAgentOutput, {});
const studentProfileMap = firstPresent(body.student_profile_map, body.studentProfileMap, body.profile_map, body.profileMap, body.student_profile_agent_output, body.studentProfileAgentOutput, {});
const userRequest = firstPresent(body.user_review_request, body.userReviewRequest, body.review_request, body.reviewRequest, body.request, {});
const strategyOptions = firstPresent(body.strategy_options, body.strategyOptions, {});

const courseId = firstPresent(body.course_id, body.courseId, evidenceFusionMap.course_id, studentProfileMap.course_id, "course_unknown");
const courseName = firstPresent(body.course_name, body.courseName, evidenceFusionMap.course_name, studentProfileMap.course_name, "Unknown Course");
const studentId = firstPresent(body.student_id, body.studentId, evidenceFusionMap.student_id, studentProfileMap.student_id, "student_unknown");

const requestAvailableTime = firstPresent(userRequest.available_time, userRequest.availableTime, body.available_time, body.availableTime, {});
const profileTime = firstPresent(studentProfileMap.time_profile, studentProfileMap.timeProfile, {});
const bodyTime = firstPresent(body.time_profile, body.timeProfile, body.time_constraints, body.timeConstraints, {});
const selectedTime = Object.keys(requestAvailableTime || {}).length ? requestAvailableTime : (Object.keys(bodyTime || {}).length ? bodyTime : profileTime);

const daysLeft = firstPresent(selectedTime.days_left, selectedTime.daysLeft, userRequest.days_left, userRequest.daysLeft, body.days_left, body.daysLeft, null);
const hoursPerDay = firstPresent(selectedTime.hours_per_day, selectedTime.hoursPerDay, userRequest.hours_per_day, userRequest.hoursPerDay, body.hours_per_day, body.hoursPerDay, null);
const explicitTotalHours = firstPresent(selectedTime.estimated_total_hours, selectedTime.estimatedTotalHours, selectedTime.total_hours, selectedTime.totalHours, userRequest.estimated_total_hours, userRequest.estimatedTotalHours, body.estimated_total_hours, body.estimatedTotalHours, null);
const estimatedTotalHours = numberOrNull(explicitTotalHours) ?? ((numberOrNull(daysLeft) !== null && numberOrNull(hoursPerDay) !== null) ? numberOrNull(daysLeft) * numberOrNull(hoursPerDay) : null);

const requestProfile = {
  raw_request: firstPresent(userRequest.raw_request, userRequest.rawRequest, userRequest.text, body.raw_request, body.rawRequest, body.text, ""),
  goal: firstPresent(userRequest.goal, userRequest.review_goal, userRequest.reviewGoal, strategyOptions.goal, "unknown"),
  target_level: firstPresent(userRequest.target_level, userRequest.targetLevel, userRequest.target_score, userRequest.targetScore, studentProfileMap.profile_summary?.target_level, studentProfileMap.profileSummary?.targetLevel, body.target_level, body.targetLevel, null),
  language: firstPresent(userRequest.language, strategyOptions.language, body.language, "zh"),
  preferred_focus: compact(firstPresent(userRequest.preferred_focus, userRequest.preferredFocus, userRequest.focus, strategyOptions.preferred_focus, strategyOptions.preferredFocus, [])),
  preferred_output: compact(firstPresent(userRequest.preferred_output, userRequest.preferredOutput, userRequest.output_format, userRequest.outputFormat, strategyOptions.preferred_output, strategyOptions.preferredOutput, [])),
  constraints: compact(firstPresent(userRequest.constraints, strategyOptions.constraints, body.constraints, []))
};

const timeProfile = {
  days_left: numberOrNull(daysLeft),
  hours_per_day: numberOrNull(hoursPerDay),
  estimated_total_hours: estimatedTotalHours,
  time_pressure: firstPresent(selectedTime.time_pressure, selectedTime.timePressure, profileTime.time_pressure, profileTime.timePressure, timePressure(estimatedTotalHours, daysLeft)),
  source_priority: Object.keys(requestAvailableTime || {}).length ? "user_review_request" : (Object.keys(bodyTime || {}).length ? "direct_input" : "student_profile_map"),
  notes: firstPresent(selectedTime.notes, profileTime.notes, null)
};

let focusCandidates = asArray(firstPresent(evidenceFusionMap.review_focus_candidates, evidenceFusionMap.reviewFocusCandidates, body.review_focus_candidates, body.reviewFocusCandidates, body.focus_candidates, body.focusCandidates, []));
const maxFocusItems = numberOrNull(firstPresent(strategyOptions.max_focus_items, strategyOptions.maxFocusItems, userRequest.max_focus_items, userRequest.maxFocusItems, null));
if (maxFocusItems !== null && maxFocusItems > 0) focusCandidates = focusCandidates.slice(0, maxFocusItems);

const inputWarnings = [];
if (!requestProfile.raw_request) inputWarnings.push("No raw user review request was provided. Strategy will rely on structured options and evidence only.");
if (!focusCandidates.length) inputWarnings.push("No review_focus_candidates were found. The final report should mark evidence as insufficient.");
if (timeProfile.estimated_total_hours === null && !timeProfile.days_left) inputWarnings.push("No clear time budget was provided. Avoid precise daily scheduling.");
if (!evidenceFusionMap || !Object.keys(evidenceFusionMap).length) inputWarnings.push("No evidence_fusion_map was provided.");

return [{
  json: {
    workflow_name: "review_strategy_critic_agent",
    course_id: courseId,
    course_name: courseName,
    student_id: studentId,
    request_profile: requestProfile,
    time_profile: timeProfile,
    strategy_options: {
      planning_style: firstPresent(strategyOptions.planning_style, strategyOptions.planningStyle, "time_boxed"),
      risk_tolerance: firstPresent(strategyOptions.risk_tolerance, strategyOptions.riskTolerance, "conservative"),
      max_focus_items: maxFocusItems ?? 8,
      include_daily_plan: firstPresent(strategyOptions.include_daily_plan, strategyOptions.includeDailyPlan, true),
      include_low_confidence_items: firstPresent(strategyOptions.include_low_confidence_items, strategyOptions.includeLowConfidenceItems, true),
      include_checklist: firstPresent(strategyOptions.include_checklist, strategyOptions.includeChecklist, true)
    },
    evidence_coverage: firstPresent(evidenceFusionMap.evidence_coverage, evidenceFusionMap.evidenceCoverage, {}),
    fusion_summary: firstPresent(evidenceFusionMap.fusion_summary, evidenceFusionMap.fusionSummary, {}),
    focus_candidates: focusCandidates,
    conflicts_or_gaps: asArray(firstPresent(evidenceFusionMap.conflicts_or_gaps, evidenceFusionMap.conflictsOrGaps, [])),
    fusion_uncertainties: asArray(firstPresent(evidenceFusionMap.uncertainties, [])),
    student_weaknesses: asArray(firstPresent(studentProfileMap.weaknesses, [])),
    mistake_patterns: asArray(firstPresent(studentProfileMap.mistake_patterns, studentProfileMap.mistakePatterns, [])),
    risk_flags: asArray(firstPresent(studentProfileMap.risk_flags, studentProfileMap.riskFlags, [])),
    learning_preferences: firstPresent(studentProfileMap.learning_preferences, studentProfileMap.learningPreferences, {}),
    input_warnings: inputWarnings,
    constraints: {
      no_exam_prediction: true,
      no_must_test_language: true,
      no_score_guarantee: true,
      every_key_recommendation_needs_evidence_basis: true,
      preserve_fusion_caveats: true,
      user_preference_can_adjust_order_but_not_override_evidence_boundary: true
    }
  }
}];

const data = $input.first().json;

function previewCandidates(candidates) {
  return (candidates || []).map(candidate => ({
    focus_id: candidate.focus_id,
    topic_or_concept: candidate.topic_or_concept,
    priority: candidate.priority,
    priority_score: candidate.priority_score,
    evidence_confidence: candidate.evidence_confidence,
    why_priority: candidate.why_priority,
    evidence_chain: candidate.evidence_chain,
    source_basis: candidate.source_basis,
    ability_targets: candidate.ability_targets,
    missing_evidence_impact: candidate.missing_evidence_impact,
    caveats: candidate.caveats,
    not_a_prediction: candidate.not_a_prediction
  }));
}

const systemPrompt = `You are Review Strategy / Critic Agent in CourseLens, a multi-agent course review system.

Your job in this step is to draft a personalized, evidence-grounded review strategy from:
1. the user's review request,
2. the Evidence Fusion Agent's review focus candidates,
3. optional student profile information.

Rules:
- Generate review strategy, not exam prediction.
- Do not use language equivalent to 必考, 押题, 今年会考, guaranteed, must-test, high probability to appear, or will appear.
- Do not guarantee scores or outcomes.
- User preferences can shape ordering and format, but cannot override evidence caveats.
- Preserve caveats from the fusion map, especially caveats about historical exam patterns.
- If time information is missing, do not invent a precise daily schedule.
- If evidence is insufficient, say so and produce a conservative strategy.
- Every high-priority item must include evidence_basis with evidence_chain or source_basis.
- Return valid JSON only. Do not wrap in Markdown.`;

const userPrompt = `Draft an Evidence-Grounded Review Report.

Course ID: ${data.course_id}
Course name: ${data.course_name}
Student ID: ${data.student_id}

User review request profile:
${JSON.stringify(data.request_profile, null, 2)}

Time profile:
${JSON.stringify(data.time_profile, null, 2)}

Strategy options:
${JSON.stringify(data.strategy_options, null, 2)}

Evidence coverage:
${JSON.stringify(data.evidence_coverage, null, 2)}

Fusion summary:
${JSON.stringify(data.fusion_summary, null, 2)}

Review focus candidates from Evidence Fusion Agent:
${JSON.stringify(previewCandidates(data.focus_candidates), null, 2)}

Student weaknesses:
${JSON.stringify(data.student_weaknesses, null, 2)}

Mistake patterns:
${JSON.stringify(data.mistake_patterns, null, 2)}

Risk flags:
${JSON.stringify(data.risk_flags, null, 2)}

Conflicts or gaps:
${JSON.stringify(data.conflicts_or_gaps, null, 2)}

Input warnings:
${JSON.stringify(data.input_warnings, null, 2)}

Return this exact JSON shape:
{
  "workflow_name": "review_strategy_critic_agent",
  "course_id": "${data.course_id}",
  "course_name": "${data.course_name}",
  "student_id": "${data.student_id}",
  "report_title": "Evidence-Grounded Review Report",
  "request_interpretation": {
    "raw_request": "string",
    "interpreted_goal": "score_improvement | pass_exam | quick_review | full_review | weak_point_fix | practice_oriented | unknown",
    "planning_style": "time_boxed | priority_only | checklist | mixed",
    "preferred_focus": ["string"],
    "preferred_output": ["string"],
    "evidence_boundary": "string"
  },
  "strategy_summary": {
    "available_study_time_hours": 12,
    "overall_strategy": "string",
    "priority_rule": "string",
    "time_allocation_rule": "string"
  },
  "prioritized_review_plan": [
    {
      "rank": 1,
      "focus_id": "rf_001_or_null",
      "topic_or_concept": "string",
      "priority": "low | medium | high",
      "recommended_time_hours": 1.5,
      "why_this_matters": "string",
      "learning_goal": "string",
      "practice_actions": ["string"],
      "success_check": ["string"],
      "evidence_basis": {
        "priority_score": 0.8,
        "evidence_confidence": 0.75,
        "source_basis": ["string"],
        "evidence_chain": ["string"],
        "caveats": ["string"]
      },
      "not_a_prediction": true
    }
  ],
  "daily_schedule": [
    {
      "day": 1,
      "estimated_hours": 4,
      "main_goal": "string",
      "tasks": [
        {
          "topic_or_concept": "string",
          "time_hours": 1.5,
          "task_type": "concept_review | calculation_practice | application_practice | mistake_review | summary | mixed",
          "expected_output": "string"
        }
      ]
    }
  ],
  "request_specific_advice": [
    {
      "user_need": "string",
      "response": "string"
    }
  ],
  "low_confidence_items": [
    {
      "topic_or_concept": "string",
