    }
  ],
  "draft_notes": {
    "used_user_constraints": ["string"],
    "preserved_caveats": ["string"]
  },
  "uncertainties": ["string"]
}

Quality requirements:
- If include_daily_plan is false or time budget is unknown, daily_schedule should be an empty array.
- Recommended time should be realistic and should not exceed available_study_time_hours when a total budget exists.
- If no focus candidates are available, produce an insufficient-evidence report with empty or very limited prioritized_review_plan.
- Keep the report useful for a student, but evidence-grounded and conservative.`;

return [{ json: { ...data, llm_payload: { system_prompt: systemPrompt, user_prompt: userPrompt } } }];

const previous = $("Build Draft Strategy Prompt").first().json;
const llmResult = $input.first().json;

function pickRawOutput(value) {
  if (typeof value === "string") return value;
  if (value?.output !== undefined) return value.output;
  if (value?.response?.text !== undefined) return value.response.text;
  if (value?.generations?.[0]?.[0]?.text !== undefined) return value.generations[0][0].text;
  if (value?.choices?.[0]?.message?.content !== undefined) return value.choices[0].message.content;
  if (value?.text !== undefined) return value.text;
  if (value?.response !== undefined) return value.response;
  if (value?.message?.content !== undefined) return value.message.content;
  return value;
}

function stripCodeFence(text) {
  const fence = String.fromCharCode(96).repeat(3);
  return text.replace(new RegExp("^" + fence + "(?:json)?\\s*", "i"), "").replace(new RegExp("\\s*" + fence + "$", "i"), "").trim();
}

function parseJsonLoose(raw) {
  if (raw && typeof raw === "object") raw = JSON.stringify(raw);
  let text = stripCodeFence(String(raw ?? "").trim());
  try {
    return JSON.parse(text);
  } catch (firstError) {
    const start = text.indexOf("{");
    const end = text.lastIndexOf("}");
    if (start >= 0 && end > start) return JSON.parse(text.slice(start, end + 1));
    throw firstError;
  }
}

let parsed;
try {
  parsed = parseJsonLoose(pickRawOutput(llmResult));
} catch (error) {
  parsed = {
    workflow_name: "review_strategy_critic_agent",
    parser_error: true,
    error_message: error.message,
    course_id: previous.course_id,
    course_name: previous.course_name,
    student_id: previous.student_id,
    report_title: "Evidence-Grounded Review Report",
    request_interpretation: {
      raw_request: previous.request_profile.raw_request || "",
      interpreted_goal: previous.request_profile.goal || "unknown",
      planning_style: previous.strategy_options.planning_style || "mixed",
      preferred_focus: previous.request_profile.preferred_focus || [],
      preferred_output: previous.request_profile.preferred_output || [],
      evidence_boundary: "This report gives review relevance suggestions only and does not predict exam content or guarantee scores."
