    draft_notes: { used_user_constraints: [], preserved_caveats: [] },
    uncertainties: ["Could not parse Draft Review Strategy output."]
  };
}

parsed.workflow_name = parsed.workflow_name || "review_strategy_critic_agent";
parsed.prioritized_review_plan = Array.isArray(parsed.prioritized_review_plan) ? parsed.prioritized_review_plan : [];
parsed.daily_schedule = Array.isArray(parsed.daily_schedule) ? parsed.daily_schedule : [];
parsed.request_specific_advice = Array.isArray(parsed.request_specific_advice) ? parsed.request_specific_advice : [];
