parsed.risk_controls = Array.isArray(parsed.risk_controls) ? parsed.risk_controls : [];
parsed.uncertainties = Array.isArray(parsed.uncertainties) ? parsed.uncertainties : [];

return [{ json: { ...previous, draft_review_report: parsed } }];

